// app/layout.js

export const metadata = {
 // Grundlegende Metadaten
 title: {
  default: 'Meine App', // Standard-Titel
  template: '%s | Meine App', // %s wird durch den Seitentitel ersetzt
 },
 // description, keywords, authors, etc.

 // Favicons und App-Icons
 icons: {
  icon: [
   { url: '/favicon.ico', sizes: 'any' },
   { url: '/icon.svg', type: 'image/svg+xml' },
  ],
  apple: '/apple-touch-icon.png', // Apple Touch Icon
  shortcut: '/favicon.ico', // Kurzform für Favicon
 },

 // Open Graph (für Social Media)
 openGraph: {
  // title, description, etc.
  images: [
   {
    url: '/og-image.png', // Bild für Social Media
    width: 1200,
    height: 630,
    alt: 'Meine App',
   },
  ],
 },

 // Robots.txt und andere Crawler-Hinweise
 robots: {
  // index, follow, nocache, etc.
 },

 // Manifest für PWA (Progressive Web App)
 manifest: '/manifest.json',

 // Viewport-Einstellungen (für Mobile)
 viewport: {
  width: 'device-width',
  initialScale: 1,
  maximumScale: 1,
  userScalable: false,
  themeColor: '#000000',
 }
};

// layout.js

import * as React from "react";
import './globals.css';

import localFont from 'next/font/local';

const fntIntro = localFont({
 src: './fonts/introheadr_base_macroman/introheadr-base-webfont.woff2',
 display: 'swap', // Fallback-Verhalten
});

export default function RootLayout({children}) {
 return (
  &lt;html lang="en" className={`my-dummy-page ${fntIntro.className}`}>
   &lt;body>
    &lt;header>
     &lt;h1>My App&lt;/h1>
    &lt;/header> 
    {children}
   &lt;/body>
  &lt;/html>
 );
}
